import styled from 'styled-components'

import { Body } from '../typography'

const Wrapper = styled.div`
  display: flex;
  align-items: center;
  justify-content: flex-start;
`

const StyledBody = styled(Body)(
  ({ theme: { color } }) => `
  display: flex;
  align-items: center;
  justify-content: flex-start;
  color: ${color.reviewText};
`
)

type ReviewProps = {
  rating?: number
}

const getReview = (rating?: number) => {
  if (!rating) {
    return 'No reviews yet'
  }

  let reviewText = 'Very poor'

  if (rating >= 2 && rating < 4) {
    reviewText = 'Adequate'
  } else if (rating >= 4 && rating < 5) {
    reviewText = 'Very good'
  } else if (rating >= 5) {
    reviewText = 'Excellent'
  }

  return `★ ${rating.toFixed(1)} ${reviewText}`
}

export const Review = ({ rating }: ReviewProps) => (
  <Wrapper>
    <StyledBody size="S" type="span" className="review-text">
      {getReview(rating)}
    </StyledBody>
  </Wrapper>
)

import styled, { useTheme } from 'styled-components'

const StyledSVG = styled.svg`
  display: block;
`

export type IconName =
  | 'arrow-right'
  | 'arrow-left'
  | 'cross'
  | 'cart'
  | 'minus'
  | 'plus'
  | 'moon'
  | 'sun'
  | 'star'

type IconProps = {
  name: IconName
  color?: string
  size?: number | string
}

export const Icon = ({ name, color, size = '1.5rem' }: IconProps) => {
  const { color: themeColor } = useTheme()
  return (
    <StyledSVG
      stroke={color || themeColor.primaryText}
      width={size}
      height={size}
      style={{ minWidth: size }}
    >
      <use xlinkHref={`/sprite-map.svg#${name}`} />
    </StyledSVG>
  )
}

